class Solution {
    public int combinationSum4(int[] nums, int target) {
        return dfs(nums, target);
    }

    private int dfs(int[] nums, int remaining) {
        if (remaining == 0) return 1;
        if (remaining < 0) return 0;
        int ways = 0;
        for (int num : nums) {
            ways += dfs(nums, remaining - num);
        }
        return ways;
    }
}

class Solution {
    public int combinationSum4(int[] nums, int target) {
        int[] memo = new int[target + 1];
        Arrays.fill(memo, -1);
        memo[0] = 1;
        return dfs(nums, target, memo);
    }

    private int dfs(int[] nums, int remaining, int[] memo) {
        if (remaining < 0) return 0;
        if (memo[remaining] != -1) return memo[remaining];
        int ways = 0;
        for (int num : nums) {
            ways += dfs(nums, remaining - num, memo);
        }
        memo[remaining] = ways;
        return ways;
    }
}

class Solution {
    public int combinationSum4(int[] nums, int target) {
        int[] dp = new int[target + 1];
        dp[0] = 1;
        for (int sum = 1; sum <= target; sum++) {
            for (int num : nums) {
                if (sum >= num) {
                    dp[sum] += dp[sum - num];
                }
            }
        }
        return dp[target];
    }
}
